{
  "version": "arkpilot-a2ui/v2",
  "kind": "semantic-ui-protocol",
  "appName": "今天吃什么",
  "targetDevice": {
    "widthVp": 1272,
    "heightVp": 2756,
    "contentMaxWidthVp": 420
  },
  "surfaces": [
    {
      "id": "home-page",
      "surfaceId": "home",
      "pageId": "home-page",
      "name": "Home",
      "route": "pages/Home",
      "tabId": "tab-home",
      "semanticTargets": [
        {
          "id": "home-greeting",
          "role": "assertion",
          "binding": "/user/greeting"
        },
        {
          "id": "home-spin-button",
          "role": "action",
          "event": "open-wheel"
        },
        {
          "id": "home-filter-mood",
          "role": "input",
          "event": "set-mood-filter"
        },
        {
          "id": "home-filter-time",
          "role": "input",
          "event": "set-time-filter"
        },
        {
          "id": "home-last-result-card",
          "role": "assertion",
          "binding": "/lastResult",
          "emptyStateId": "home-no-result-yet"
        },
        {
          "id": "home-quick-checkin-button",
          "role": "action",
          "event": "open-checkin-sheet"
        }
      ]
    },
    {
      "id": "wheel-page",
      "surfaceId": "wheel",
      "pageId": "wheel-page",
      "name": "Wheel",
      "route": "pages/Wheel",
      "semanticTargets": [
        {
          "id": "wheel-back-button",
          "role": "action",
          "event": "navigate-back"
        },
        {
          "id": "wheel-canvas",
          "role": "assertion",
          "binding": "/wheel/state"
        },
        {
          "id": "wheel-spin-trigger",
          "role": "action",
          "event": "spin-wheel"
        },
        {
          "id": "wheel-result-name",
          "role": "assertion",
          "binding": "/wheel/result/name"
        },
        {
          "id": "wheel-result-tags",
          "role": "assertion",
          "binding": "/wheel/result/tags"
        },
        {
          "id": "wheel-accept-button",
          "role": "action",
          "event": "accept-result"
        },
        {
          "id": "wheel-retry-button",
          "role": "action",
          "event": "retry-spin"
        },
        {
          "id": "wheel-filter-chip-group",
          "role": "input",
          "event": "toggle-filter"
        }
      ]
    },
    {
      "id": "fridge-page",
      "surfaceId": "fridge",
      "pageId": "fridge-page",
      "name": "Fridge",
      "route": "pages/Fridge",
      "tabId": "tab-fridge",
      "semanticTargets": [
        {
          "id": "fridge-ingredient-input",
          "role": "input",
          "event": "add-ingredient"
        },
        {
          "id": "fridge-add-button",
          "role": "action",
          "event": "confirm-add-ingredient"
        },
        {
          "id": "fridge-ingredient-list",
          "role": "list",
          "binding": "/fridge/ingredients",
          "itemIdPattern": "fridge-ingredient-{id}",
          "emptyStateId": "fridge-empty-state"
        },
        {
          "id": "fridge-remove-button",
          "role": "action",
          "event": "remove-ingredient"
        },
        {
          "id": "fridge-matched-dish-list",
          "role": "list",
          "binding": "/fridge/matchedDishes",
          "itemIdPattern": "fridge-dish-{id}",
          "emptyStateId": "fridge-no-match-state"
        },
        {
          "id": "fridge-clear-all-button",
          "role": "action",
          "event": "clear-ingredients"
        }
      ]
    },
    {
      "id": "checkin-page",
      "surfaceId": "checkin",
      "pageId": "checkin-page",
      "name": "CheckIn",
      "route": "pages/CheckIn",
      "tabId": "tab-checkin",
      "semanticTargets": [
        {
          "id": "checkin-today-date",
          "role": "assertion",
          "binding": "/checkin/todayDate"
        },
        {
          "id": "checkin-add-button",
          "role": "action",
          "event": "open-checkin-sheet"
        },
        {
          "id": "checkin-timeline-list",
          "role": "list",
          "binding": "/checkin/todayItems",
          "itemIdPattern": "checkin-item-{id}",
          "emptyStateId": "checkin-empty-state"
        },
        {
          "id": "checkin-week-summary",
          "role": "assertion",
          "binding": "/checkin/weekSummary"
        },
        {
          "id": "checkin-sheet-dish-name",
          "role": "input",
          "event": "set-checkin-dish"
        },
        {
          "id": "checkin-sheet-note",
          "role": "input",
          "event": "set-checkin-note"
        },
        {
          "id": "checkin-sheet-meal-type",
          "role": "input",
          "event": "set-meal-type"
        },
        {
          "id": "checkin-sheet-save-button",
          "role": "action",
          "event": "save-checkin"
        },
        {
          "id": "checkin-sheet-cancel-button",
          "role": "action",
          "event": "close-checkin-sheet"
        }
      ]
    },
    {
      "id": "share-page",
      "surfaceId": "share",
      "pageId": "share-page",
      "name": "Share",
      "route": "pages/Share",
      "semanticTargets": [
        {
          "id": "share-back-button",
          "role": "action",
          "event": "navigate-back"
        },
        {
          "id": "share-card-preview",
          "role": "assertion",
          "binding": "/share/cardData"
        },
        {
          "id": "share-card-title",
          "role": "assertion",
          "binding": "/share/cardData/title"
        },
        {
          "id": "share-card-caption",
          "role": "input",
          "event": "edit-share-caption"
        },
        {
          "id": "share-card-theme-picker",
          "role": "input",
          "event": "set-share-theme"
        },
        {
          "id": "share-system-button",
          "role": "action",
          "event": "share-to-system"
        },
        {
          "id": "share-save-image-button",
          "role": "action",
          "event": "save-card-image"
        }
      ]
    },
    {
      "id": "profile-page",
      "surfaceId": "profile",
      "pageId": "profile-page",
      "name": "Profile",
      "route": "pages/Profile",
      "tabId": "tab-profile",
      "semanticTargets": [
        {
          "id": "profile-cuisine-preference",
          "role": "input",
          "event": "toggle-cuisine"
        },
        {
          "id": "profile-dietary-restriction",
          "role": "input",
          "event": "toggle-dietary"
        },
        {
          "id": "profile-clear-history-button",
          "role": "action",
          "event": "clear-history"
        },
        {
          "id": "profile-export-data-button",
          "role": "action",
          "event": "export-data"
        }
      ]
    }
  ],
  "events": {
    "open-wheel": { "source": ["home-spin-button"], "description": "Navigate to the wheel page to start a spin." },
    "spin-wheel": { "source": ["wheel-spin-trigger"], "description": "Trigger wheel animation and compute a dish result." },
    "accept-result": { "source": ["wheel-accept-button"], "description": "Accept the wheel result and optionally log it." },
    "retry-spin": { "source": ["wheel-retry-button"], "description": "Spin the wheel again." },
    "set-mood-filter": { "source": ["home-filter-mood", "wheel-filter-chip-group"], "description": "Set or clear the current mood filter." },
    "set-time-filter": { "source": ["home-filter-time", "wheel-filter-chip-group"], "description": "Set or clear the current time/cooking-time filter." },
    "toggle-filter": { "source": ["wheel-filter-chip-group"], "description": "Toggle a quick filter chip on the wheel page." },
    "add-ingredient": { "source": ["fridge-ingredient-input"], "description": "Input an ingredient name." },
    "confirm-add-ingredient": { "source": ["fridge-add-button"], "description": "Add the ingredient to the fridge list." },
    "remove-ingredient": { "source": ["fridge-remove-button"], "description": "Remove a single ingredient from the list." },
    "clear-ingredients": { "source": ["fridge-clear-all-button"], "description": "Clear all fridge ingredients." },
    "open-checkin-sheet": { "source": ["home-quick-checkin-button", "checkin-add-button"], "description": "Open the add-check-in bottom sheet." },
    "close-checkin-sheet": { "source": ["checkin-sheet-cancel-button"], "description": "Close the add-check-in sheet without saving." },
    "set-checkin-dish": { "source": ["checkin-sheet-dish-name"], "description": "Set the dish name for the check-in." },
    "set-checkin-note": { "source": ["checkin-sheet-note"], "description": "Set an optional note for the check-in." },
    "set-meal-type": { "source": ["checkin-sheet-meal-type"], "description": "Set breakfast/lunch/dinner/snack." },
    "save-checkin": { "source": ["checkin-sheet-save-button"], "description": "Save the new check-in item." },
    "share-to-system": { "source": ["share-system-button"], "description": "Trigger the system share sheet with card content." },
    "save-card-image": { "source": ["share-save-image-button"], "description": "Save the generated share card as an image." },
    "edit-share-caption": { "source": ["share-card-caption"], "description": "Edit the share card caption text." },
    "set-share-theme": { "source": ["share-card-theme-picker"], "description": "Pick a visual theme for the share card." },
    "toggle-cuisine": { "source": ["profile-cuisine-preference"], "description": "Toggle a cuisine preference." },
    "toggle-dietary": { "source": ["profile-dietary-restriction"], "description": "Toggle a dietary restriction." },
    "clear-history": { "source": ["profile-clear-history-button"], "description": "Clear all check-in history." },
    "export-data": { "source": ["profile-export-data-button"], "description": "Export local data for backup." },
    "navigate-back": { "source": ["wheel-back-button", "share-back-button"], "description": "Return to the previous page." }
  },
  "bindings": {
    "/user/greeting": { "type": "string", "description": "Personalized greeting based on time of day." },
    "/lastResult": { "type": "object|null", "description": "Most recent wheel result dish object." },
    "/wheel/state": { "type": "enum", "values": ["idle", "spinning", "result"], "description": "Current wheel animation state." },
    "/wheel/result/name": { "type": "string", "description": "Name of the dish selected by the wheel." },
    "/wheel/result/tags": { "type": "string[]", "description": "Tags associated with the selected dish." },
    "/fridge/ingredients": { "type": "string[]", "description": "List of user-added ingredient names." },
    "/fridge/matchedDishes": { "type": "object[]", "description": "Dishes that can be made from current ingredients." },
    "/checkin/todayDate": { "type": "string", "description": "Formatted date for today." },
    "/checkin/todayItems": { "type": "object[]", "description": "Today’s logged meal items." },
    "/checkin/weekSummary": { "type": "object", "description": "Weekly check-in count summary." },
    "/share/cardData": { "type": "object", "description": "Data rendered on the share card." }
  },
  "testTargets": {
    "bottom-tab-bar": ["tab-home", "tab-fridge", "tab-checkin", "tab-profile"],
    "empty-states": [
      "home-no-result-yet",
      "fridge-empty-state",
      "fridge-no-match-state",
      "checkin-empty-state"
    ],
    "wheel-result-actions": ["wheel-accept-button", "wheel-retry-button"],
    "share-actions": ["share-system-button", "share-save-image-button"]
  }
}

